from flask import Flask, request, jsonify
import requests
from bs4 import BeautifulSoup
from selenium import webdriver
from selenium.webdriver.chrome.service import Service
from webdriver_manager.chrome import ChromeDriverManager
from PIL import Image
import io
import boto3

app = Flask(__name__)

def take_screenshot(url):
    chrome_options = webdriver.ChromeOptions()
    chrome_options.add_argument('--headless')
    chrome_options.add_argument('--disable-gpu')
    chrome_options.add_argument('--window-size=1280x1024')

    service = Service(ChromeDriverManager().install())
    driver = webdriver.Chrome(service=service, options=chrome_options)

    try:
        driver.get(url)
        screenshot = driver.get_screenshot_as_png()
        return screenshot
    finally:
        driver.quit()

@app.route('/screenshot', methods=['POST'])
def capture_screenshot():
    data = request.json
    url = data['url']
    
    if not url:
        return jsonify({'error': 'URL is required'}), 400

    try:
        screenshot = take_screenshot(url)
        
        # Resize the screenshot to thumbnail size (e.g., 300x200 pixels)
        image = Image.open(io.BytesIO(screenshot))
        image.thumbnail((300, 200))

        output = io.BytesIO()
        image.convert("RGB").save(output, "JPEG")
        output.seek(0)

        # Save screenshot to S3
        s3_client = boto3.client('s3', aws_access_key_id='YOUR_ACCESS_KEY',
                                aws_secret_access_key='YOUR_SECRET_KEY')
        bucket_name = 'your-bucket-name'
        file_name = f"screenshot_{url.replace('/', '_')}.jpg"
        
        s3_client.put_object(Body=output, Bucket=bucket_name, Key=file_name)

        return jsonify({'message': 'Screenshot saved', 's3_url': f'https://{bucket_name}.s3.amazonaws.com/{file_name}'}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=80)